module adder(a, b, cin, sum, cout);
  input a;
  wire a;
  input b;
  wire b;
  input cin;
  wire cin;
  output sum;
  wire sum;
  output cout;
  wire cout;
  wire _0_;
  wire _1_;
  wire _2_;
  wire _3_;
  wire out1;
  wire out2;
  wire out3;
  wire out4;
  INV_X1 _4_ (
    .A(b),
    .ZN(_1_)
  );
  INV_X1 _5_ (
    .A(cin),
    .ZN(_0_)
  );
  LOGIC1_X1 _6_ (
    .Z(_2_)
  );
  LOGIC0_X1 _7_ (
    .Z(_3_)
  );
  mux mux1 (
    .in({ _0_, cin }),
    .out(out1),
    .sel(b)
  );
  mux mux2 (
    .in({ b, _1_ }),
    .out(out2),
    .sel(cin)
  );
  mux mux3 (
    .in({ out2, out1 }),
    .out(sum),
    .sel(a)
  );
  mux mux4 (
    .in({ _2_, cin }),
    .out(out3),
    .sel(b)
  );
  mux mux5 (
    .in({ b, _3_ }),
    .out(out4),
    .sel(cin)
  );
  mux mux6 (
    .in({ out3, out4 }),
    .out(cout),
    .sel(a)
  );
endmodule

